import React, { useState, useRef, useEffect } from "react";
import FileUpload from "./components/FileUpload";
import Results from "./components/Results";
import "./App.css";

export default function App() {
  const [phase, setPhase]   = useState("upload"); // upload | pipeline | results
  const [steps, setSteps]   = useState([]);
  const [error, setError]   = useState(null);
  const [result, setResult] = useState(null);

  const handleUpload = async (file) => {
    setPhase("pipeline");
    setError(null);
    setResult(null);
    setSteps([{ stage: "__start__", status: "running", title: `Reading "${file.name}"…`, lines: [] }]);

    const formData = new FormData();
    formData.append("file", file);

    try {
      const res = await fetch("http://localhost:8000/cluster", {
        method: "POST",
        body: formData,
      });

      if (!res.ok) {
        const data = await res.json();
        throw new Error(data.detail || "Server error");
      }

      const reader  = res.body.getReader();
      const decoder = new TextDecoder();
      let   buffer  = "";

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        buffer += decoder.decode(value, { stream: true });
        const parts = buffer.split("\n\n");
        buffer = parts.pop();

        for (const part of parts) {
          if (!part.trim()) continue;

          let eventType = "message";
          let dataLine  = "";
          for (const line of part.split("\n")) {
            if (line.startsWith("event: ")) eventType = line.slice(7).trim();
            if (line.startsWith("data: "))  dataLine  = line.slice(6).trim();
          }
          if (!dataLine) continue;

          let payload;
          try { payload = JSON.parse(dataLine); } catch { continue; }

          if (eventType === "step") {
            setSteps((prev) => {
              const next = prev.map((s) =>
                s.status === "running" ? { ...s, status: "done" } : s
              );
              next.push({
                stage:  payload.stage,
                status: "running",
                title:  payload.title,
                detail: payload.detail || "",
                warn:   payload.warn || false,
                lines:  buildLines(payload),
              });
              return next;
            });
          } else if (eventType === "error") {
            setSteps((prev) => prev.map((s, i) =>
              i === prev.length - 1 ? { ...s, status: "error" } : s
            ));
            setError(payload.message || "Pipeline error");
          } else if (eventType === "done") {
            setSteps((prev) => prev.map((s) =>
              s.status === "running" ? { ...s, status: "done" } : s
            ));
            setTimeout(() => {
              setResult(payload);
              setPhase("results");
            }, 700);
          }
        }
      }
    } catch (e) {
      setError(e.message);
      setSteps((prev) => prev.map((s, i) =>
        i === prev.length - 1 ? { ...s, status: "error" } : s
      ));
    }
  };

  const handleReset = () => {
    setPhase("upload");
    setSteps([]);
    setResult(null);
    setError(null);
  };

  return (
    <div className="app">
      <header className="header">
        <div className="header-inner">
          <div className="logo">
            <span className="logo-mark">▣</span>
            <span className="logo-text">RFM<span className="logo-accent">seg</span></span>
          </div>
          <p className="header-sub">Customer Segmentation Engine</p>
        </div>
      </header>

      <main className="main">
        {phase === "upload"   && <FileUpload onUpload={handleUpload} error={error} />}
        {phase === "pipeline" && <Pipeline steps={steps} error={error} onReset={handleReset} />}
        {phase === "results"  && <Results data={result} onReset={handleReset} />}
      </main>
    </div>
  );
}

// ── Build display lines from a step payload ────────────────────────────────
function buildLines(payload) {
  const lines = [];
  if (payload.detail) {
    payload.detail.split(/\s+·\s+/).forEach((p) => {
      if (p.trim()) lines.push(p.trim());
    });
  }
  if (payload.sil_scores) {
    lines.push({ type: "sil", scores: payload.sil_scores });
  }
  return lines;
}

// ── Stage icon map ─────────────────────────────────────────────────────────
const STAGE_ICONS = {
  __start__:    "📁",
  parse:        "📂",
  columns:      "🔍",
  clean:        "🧹",
  monetary:     "💰",
  frequency:    "🔁",
  monetary_agg: "📊",
  recency:      "📅",
  rfm:          "🧮",
  scale:        "⚖️",
  best_k:       "✅",
  profiles:     "🏷️",
};

// ── Pipeline component ─────────────────────────────────────────────────────
function Pipeline({ steps, error, onReset }) {
  const bottomRef = useRef(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth", block: "nearest" });
  }, [steps.length]);

  return (
    <div className="pipeline">
      <div className="pipeline-header">
        <span className="pipeline-title">Processing your dataset</span>
        <span className="pipeline-hint">Each step completes before the next begins</span>
      </div>

      <div className="pipeline-feed">
        {steps.map((step, i) => (
          <StepBlock key={`${step.stage}-${i}`} step={step} isLast={i === steps.length - 1} />
        ))}

        {error && !steps.some(s => s.status === "error") && (
          <div className="step-error-block">
            <span className="step-error-icon">✖</span>
            <div>
              <p className="step-error-title">Something went wrong</p>
              <p className="step-error-msg">{error}</p>
            </div>
            <button className="retry-btn" onClick={onReset}>↩ Try again</button>
          </div>
        )}

        {error && steps.some(s => s.status === "error") && (
          <div className="step-error-inline">
            <p className="step-error-msg">{error}</p>
            <button className="retry-btn" onClick={onReset}>↩ Try again</button>
          </div>
        )}

        <div ref={bottomRef} />
      </div>
    </div>
  );
}

// ── Single step block ──────────────────────────────────────────────────────
function StepBlock({ step, isLast }) {
  const isDone    = step.status === "done";
  const isRunning = step.status === "running";
  const isError   = step.status === "error";

  const icon = STAGE_ICONS[step.stage] ?? (step.stage?.startsWith("k") ? "🔬" : "⚙️");

  const silLine = step.lines?.find((l) => l?.type === "sil");
  const bestK   = silLine
    ? Object.entries(silLine.scores).sort((a, b) => b[1] - a[1])[0]?.[0]
    : null;

  return (
    <div className={`step-block
      ${isDone    ? "step-done"    : ""}
      ${isRunning ? "step-running" : ""}
      ${isError   ? "step-error"   : ""}
      ${step.warn ? "step-warn"    : ""}
    `}>
      {/* ── Circle node ── */}
      <div className="step-node">
        {isDone  && <span className="node-check">✓</span>}
        {isRunning && <ThreeDots />}
        {isError && <span className="node-x">✕</span>}
      </div>

      {/* ── Connector line ── */}
      {!isLast && <div className="step-connector" />}

      {/* ── Content ── */}
      <div className="step-content">
        <div className="step-head">
          <span className="step-emoji">{icon}</span>
          <span className="step-title-text">{step.title}</span>
        </div>

        {/* Detail lines — only show when done or running (not the placeholder) */}
        {step.lines?.length > 0 && step.stage !== "__start__" && (
          <div className="step-body">
            {step.lines.map((line, i) => {
              if (line?.type === "sil") {
                const entries = Object.entries(line.scores);
                const maxScore = Math.max(...entries.map(([, v]) => v));
                return (
                  <div key={i} className="sil-inline">
                    <p className="sil-inline-label">Silhouette scores tested so far</p>
                    {entries.map(([k, v]) => (
                      <div key={k} className="sil-inline-row">
                        <span className="sil-k">k={k}</span>
                        <div className="sil-track">
                          <div
                            className={`sil-fill ${String(k) === String(bestK) ? "sil-best" : ""}`}
                            style={{ width: `${(v / maxScore) * 100}%` }}
                          />
                        </div>
                        <span className={`sil-score ${String(k) === String(bestK) ? "sil-score-best" : ""}`}>
                          {v.toFixed(4)}{String(k) === String(bestK) ? " ← best" : ""}
                        </span>
                      </div>
                    ))}
                  </div>
                );
              }
              return (
                <div key={i} className="step-line">
                  <span className="step-line-bullet">–</span>
                  <span className="step-line-text">{line}</span>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

// ── Three animated dots ────────────────────────────────────────────────────
function ThreeDots() {
  return (
    <span className="three-dots">
      <span className="dot" />
      <span className="dot" />
      <span className="dot" />
    </span>
  );
}
